-- ============================================================
-- IDOM ハンズオン: 環境セットアップ
-- ============================================================
-- このスクリプトはハンズオンの前提環境を構築します
-- 所要時間: 約5分（データ投入を含む）
--
-- 作成されるオブジェクト:
--   - IDOM_HANDSON データベース
--   - RAW_DATA スキーマ（4テーブル + サンプルデータ）
--   - DATA_MART スキーマ（空: ハンズオンで構築）
--   - AGENTS スキーマ（空: ハンズオンで構築）
--   - Git API Integration（Workspace 用）
-- ============================================================

USE ROLE ACCOUNTADMIN;
USE WAREHOUSE COMPUTE_WH;

-- ============================================================
-- 1. DATABASE & SCHEMAS
-- ============================================================
CREATE DATABASE IF NOT EXISTS IDOM_HANDSON;
CREATE SCHEMA IF NOT EXISTS IDOM_HANDSON.RAW_DATA;
CREATE SCHEMA IF NOT EXISTS IDOM_HANDSON.DATA_MART;
CREATE SCHEMA IF NOT EXISTS IDOM_HANDSON.AGENTS;

-- ============================================================
-- 2. RAW_DATA TABLES
-- ============================================================
USE SCHEMA IDOM_HANDSON.RAW_DATA;

CREATE OR REPLACE TABLE IDOM_HANDSON.RAW_DATA.STORES (
	STORE_ID VARCHAR(20) NOT NULL,
	STORE_NAME VARCHAR(100),
	REGION VARCHAR(50),
	PREFECTURE VARCHAR(20),
	CITY VARCHAR(50),
	STORE_TYPE VARCHAR(30),
	OPENING_DATE DATE,
	MANAGER_NAME VARCHAR(50),
	TARGET_MONTHLY_SALES NUMBER(12,0),
	TARGET_MONTHLY_CONTRACTS NUMBER(10,0),
	IS_ACTIVE BOOLEAN DEFAULT TRUE,
	CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
	primary key (STORE_ID)
);

CREATE OR REPLACE TABLE IDOM_HANDSON.RAW_DATA.CONTRACTS (
	CONTRACT_ID VARCHAR(20) NOT NULL,
	NEGOTIATION_ID VARCHAR(20),
	STORE_ID VARCHAR(20),
	CUSTOMER_NAME VARCHAR(50),
	CAR_NAME VARCHAR(100),
	CONTRACT_TYPE VARCHAR(20),
	CONTRACT_PRICE NUMBER(12,0),
	TAX_AMOUNT NUMBER(12,0),
	PAYMENT_METHOD VARCHAR(30),
	LOAN_AMOUNT NUMBER(12,0),
	LOAN_TERM_MONTHS NUMBER(5,0),
	CONTRACT_DATE DATE,
	DELIVERY_DATE DATE,
	CONTRACT_STATUS VARCHAR(20),
	CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
	primary key (CONTRACT_ID)
);

CREATE OR REPLACE TABLE IDOM_HANDSON.RAW_DATA.INSURANCE (
	INSURANCE_ID VARCHAR(20) NOT NULL,
	CONTRACT_ID VARCHAR(20),
	STORE_ID VARCHAR(20),
	CUSTOMER_NAME VARCHAR(50),
	INSURANCE_TYPE VARCHAR(30),
	INSURANCE_COMPANY VARCHAR(50),
	PREMIUM_AMOUNT NUMBER(10,0),
	COVERAGE_START DATE,
	COVERAGE_END DATE,
	IS_NEW_CONTRACT BOOLEAN,
	CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
	primary key (INSURANCE_ID)
);

CREATE OR REPLACE TABLE IDOM_HANDSON.RAW_DATA.ACTIVITY_LOGS (
	RAW_DATA VARIANT
);

