  ('{"activity_id": "ACT0096", "negotiation_id": "N0620", "store_id": "S004", "customer_name": "中田裕子", "assigned_user_name": "石井由美", "activity_type": "社内メモ", "activity_date": "2026-04-19 10:15:00", "subject": "商談状況の共有", "body": "中田裕子様のスバル フォレスター商談について店長と共有。価格交渉の余地と競合状況を分析。今後のフォロー方針を決定。顧客の温度感は中程度、継続的なフォローが必要と判断。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0097", "negotiation_id": "N0620", "store_id": "S003", "customer_name": "清水拓也", "assigned_user_name": "鈴木一郎", "activity_type": "LINE", "activity_date": "2026-03-03 20:15:00", "subject": "LINEでの問合せ対応", "body": "清水拓也様よりLINE。「スズキ ジムニーの在庫状況を教えてください」とのメッセージ。在庫写真を送付し、スペックと価格情報をご案内。来店を提案し、アポを調整中。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0098", "negotiation_id": "N0620", "store_id": "S006", "customer_name": "瀬戸浩二", "assigned_user_name": "藤田康平", "activity_type": "電話（受信）", "activity_date": "2026-03-14 11:30:00", "subject": "納車後フォロー", "body": "瀬戸浩二様より入電。先日納車したホンダ ヴェゼルの調子を確認。「快適に乗っています」とのこと。オイル交換の時期についてご質問あり→次回点検時に実施する旨ご案内。知人への紹介もいただける可能性あり。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0099", "negotiation_id": "N0620", "store_id": "S007", "customer_name": "大西康平", "assigned_user_name": "中村恵子", "activity_type": "来店対応", "activity_date": "2026-03-02 10:45:00", "subject": "来店ヒアリング・車両確認", "body": "大西康平様来店。トヨタ アルファードの実車を確認。内装の状態に満足された様子。試乗を実施し、「走りが良い」と好感触。見積書を作成し、総額495万円（税込）で提示。下取り査定も実施。「少し検討したい」とのことで、翌週にご連絡いただく約束。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0100", "negotiation_id": "N0621", "store_id": "S001", "customer_name": "岡本沙織", "assigned_user_name": "山本直樹", "activity_type": "契約手続き", "activity_date": "2026-03-29 14:15:00", "subject": "契約完了", "body": "岡本沙織様来店、電子売契にて契約完了。マツダ CX-5の総額125万円。支払方法確定。納車予定日を調整。保険の切替についてもご案内済み。328様「対応が丁寧で安心して購入できた」とコメント。", "created_at": "2026-04-07 21:15:46.102000"}');

