  ('{"activity_id": "ACT0243", "negotiation_id": "N0733", "store_id": "S007", "customer_name": "斎藤恵", "assigned_user_name": "加藤明美", "activity_type": "来店対応", "activity_date": "2026-04-10 12:15:00", "subject": "来店ヒアリング・車両確認", "body": "斎藤恵様来店。スバル フォレスターの実車を確認。内装の状態に満足された様子。試乗を実施し、「走りが良い」と好感触。見積書を作成し、総額311万円（税込）で提示。下取り査定も実施。「少し検討したい」とのことで、翌週にご連絡いただく約束。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0244", "negotiation_id": "N0737", "store_id": "S006", "customer_name": "片桐美咲", "assigned_user_name": "中村麻衣", "activity_type": "LINE", "activity_date": "2026-04-13 12:30:00", "subject": "LINEでの問合せ対応", "body": "片桐美咲様よりLINE。「トヨタ プリウスの在庫状況を教えてください」とのメッセージ。在庫写真を送付し、スペックと価格情報をご案内。来店を提案し、アポを調整中。", "created_at": "2026-04-07 21:15:46.102000"}'),
